from abc import ABC, abstractmethod
from typing import Dict

class HybridExecutor(ABC):
    def __init__(self, fallback_enabled: bool = True):
        self.fallback_enabled = fallback_enabled

    @abstractmethod
    def quantum_solve(self, problem: Dict) -> Dict:
        pass

    @abstractmethod
    def classical_solve(self, problem: Dict) -> Dict:
        pass

    def execute(self, problem: Dict, min_quality: float = 0.8) -> Dict:
        try:
            result = self.quantum_solve(problem)
            result['mode'] = 'quantum'

            if result.get('quality', 1.0) < min_quality and self.fallback_enabled:
                classical_result = self.classical_solve(problem)
                classical_result['mode'] = 'fallback'
                classical_result['quantum_quality'] = result.get('quality')
                return classical_result

            return result
        except Exception as e:
            if self.fallback_enabled:
                result = self.classical_solve(problem)
                result['mode'] = 'fallback'
                result['error'] = str(e)
                return result
            raise

class SimpleHybridExecutor(HybridExecutor):
    def quantum_solve(self, problem: Dict) -> Dict:
        import random
        return {'result': problem.get('value', 0) * 1.1, 'quality': random.uniform(0.5, 1.0)}

    def classical_solve(self, problem: Dict) -> Dict:
        return {'result': problem.get('value', 0), 'quality': 1.0}

import numpy as np
from typing import Dict, List

class QuantumEncoder:
    def encode_amplitudes(self, data: np.ndarray) -> Dict:
        # Normalize to unit vector
        norm = np.linalg.norm(data)
        if norm > 0:
            amplitudes = data / norm
        else:
            amplitudes = data

        # Convert to RY angles: amplitude = sin(theta/2)
        # So theta = 2 * arcsin(amplitude)
        angles = 2 * np.arcsin(np.clip(np.sqrt(np.abs(amplitudes)), 0, 1))

        return {
            'angles': angles.tolist(),
            'normalization': float(norm),
            'num_qubits': int(np.ceil(np.log2(len(data))))
        }

    def decode_measurements(self, counts: Dict[str, int]) -> np.ndarray:
        total = sum(counts.values())
        n_bits = len(next(iter(counts)))
        probs = np.zeros(2 ** n_bits)

        for state, count in counts.items():
            idx = int(state, 2)
            probs[idx] = count / total

        return probs

