from dataclasses import dataclass
from typing import Dict, Callable, List, Optional
import time

@dataclass
class Step:
    name: str
    func: Callable
    timeout: float
    fallback: Optional[Callable] = None

class Workflow:
    def __init__(self):
        self.steps: List[Step] = []
        self.results: Dict[str, Dict] = {}

    def add_step(self, step: Step):
        self.steps.append(step)

    def run(self, data: Dict) -> Dict:
        current_data = data.copy()

        for step in self.steps:
            start = time.time()
            try:
                result = step.func(current_data)
                elapsed = time.time() - start

                if elapsed > step.timeout and step.fallback:
                    result = step.fallback(current_data)
                    self.results[step.name] = {'status': 'timeout_fallback', 'result': result}
                else:
                    self.results[step.name] = {'status': 'success', 'result': result, 'time': elapsed}

                current_data.update(result)

            except Exception as e:
                if step.fallback:
                    result = step.fallback(current_data)
                    self.results[step.name] = {'status': 'fallback', 'result': result, 'error': str(e)}
                    current_data.update(result)
                else:
                    self.results[step.name] = {'status': 'failed', 'error': str(e)}
                    return {'error': str(e), 'step': step.name}

        return current_data

